const crypto = require('crypto');
const item = $input.first();
const input = item.json;
const headers = input.headers || {};
const signature = headers['stripe-signature'] || headers['Stripe-Signature'];

function readRawBody() {
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      const bin = item.binary[key];
      if (bin && bin.data) {
        return Buffer.from(bin.data, bin.encoding || 'base64').toString('utf8');
      }
    }
  }
  if (typeof input.body === 'string') return input.body;
  if (Buffer.isBuffer(input.body)) return input.body.toString('utf8');
  if (input.body && input.body.type === 'Buffer' && Array.isArray(input.body.data)) {
    return Buffer.from(input.body.data).toString('utf8');
  }
  return null;
}

const skipVerify = String($env.STRIPE_WEBHOOK_SKIP_VERIFY || 'false').toLowerCase() === 'true';
let rawBody = readRawBody();

if (skipVerify) {
  // LOCAL DEV ONLY — n8n often parses JSON before Code runs; HMAC cannot be verified on re-serialized body.
  let event;
  if (rawBody) {
    event = JSON.parse(rawBody);
  } else if (input.body && input.body.type && input.body.data) {
    event = input.body;
  } else if (input.type && input.data) {
    event = input;
  } else {
    throw new Error('STRIPE_WEBHOOK_SKIP_VERIFY: could not parse Stripe event');
  }
  return [{
    json: {
      event,
      rawBody: rawBody || JSON.stringify(event),
      signature_verified: false,
      verify_mode: 'skipped_local',
    },
  }];
}

if (!signature) throw new Error('Missing Stripe-Signature header');
if (!rawBody) {
  throw new Error(
    'Stripe requires the raw webhook body for signature verification. ' +
    'Ensure Webhook rawBody is enabled. For local testing only: STRIPE_WEBHOOK_SKIP_VERIFY=true'
  );
}

const secret = $env.STRIPE_WEBHOOK_SECRET;
if (!secret) throw new Error('Set STRIPE_WEBHOOK_SECRET on the n8n container');

const elements = signature.split(',');
let timestamp = '';
const v1s = [];
for (const el of elements) {
  const [k, v] = el.split('=');
  if (k === 't') timestamp = v;
  if (k === 'v1') v1s.push(v);
}
const expected = crypto.createHmac('sha256', secret).update(timestamp + '.' + rawBody, 'utf8').digest('hex');
const valid = v1s.some((sig) => {
  try {
    return crypto.timingSafeEqual(Buffer.from(sig, 'hex'), Buffer.from(expected, 'hex'));
  } catch {
    return false;
  }
});
if (!valid) throw new Error('Invalid Stripe webhook signature');

const event = JSON.parse(rawBody);
return [{
  json: {
    event,
    rawBody,
    signature_verified: true,
    verify_mode: 'strict',
  },
}];

const event = $json.event;
if (event.type !== 'checkout.session.completed') {
  return [{
    json: {
      skip: true,
      event_type: event.type,
      stripe_event_id: event.id,
      message: 'Event acknowledged, no payment write',
    },
  }];
}

const session = event.data.object;
const paymentKind = session.metadata?.payment_kind === 'full_amount' ? 'full_amount' : 'deposit_only';
const bookingId = session.metadata?.booking_id;
if (!bookingId) {
  throw new Error('checkout.session.completed missing metadata.booking_id');
}

const amountPaid = session.amount_total ?? 0;
const paymentIntent = typeof session.payment_intent === 'string'
  ? session.payment_intent
  : (session.payment_intent?.id || null);

return [{
  json: {
    skip: false,
    stripe_event_id: event.id,
    event_type: event.type,
    session_id: session.id,
    payment_intent_id: paymentIntent,
    booking_id: bookingId,
    client_id: session.metadata?.client_id || null,
    payment_kind: paymentKind,
    amount_paid_cents: amountPaid,
    payload: event,
  },
}];
